class AsceticTracker:
    def __init__(self):
        self.days_fasted = 0
        self.material_possessions = 0
        self.prayer_hours = 0

    def fast(self):
        self.days_fasted += 1

    def add_possession(self, count=1):
        self.material_possessions += count

    def log_prayer(self, hours):
        self.prayer_hours += hours

    def get_stats(self):
        return {
            'days_fasted': self.days_fasted,
            'possessions': self.material_possessions,
            'prayer_hours': self.prayer_hours
        }

# Example usage:
tracker = AsceticTracker()
tracker.fast()
tracker.fast()
tracker.log_prayer(2)
tracker.add_possession(0)  # No new possessions added
print(tracker.get_stats())  # Output: {'days_fasted': 2, 'possessions': 0, 'prayer_hours': 2}
